def verify(response):
    import re
    code_match = re.search(r"```python\n([\s\S]*?)```", response)
    if not code_match:
        code_match = re.search(r"```\n([\s\S]*?)```", response)
    if not code_match:
        code = response
    else:
        code = code_match.group(1)

    sandbox = {}
    try:
        exec(code, sandbox)
        if 'solve' not in sandbox:
            return False
        fn = sandbox['solve']
        test_cases = [('()', True), ('()[]{}', True), ('(]', False), ('([)]', False), ('{[]}', True), ('', True)]
        for inp, expected in test_cases:
            if fn(inp) != expected:
                return False
        return True
    except Exception as e:
        return False
